    60→/* ------------------------------------------------------------------ */
    61→/* Representative 100-point test                                       */
    62→/* ------------------------------------------------------------------ */
    63→
    64→static void test_representative_100(void)
    65→{
    66→    /* --- Section 1: Special IEEE 754 values (8) --- */
    67→    emit(0.0);                                     /* log(0) = -Inf */
    68→    emit(-0.0);                                    /* log(-0) = -Inf */
    69→    emit_u(0x7ff8000000000000ULL);                 /* qNaN */
    70→    emit_u(0x7ff0000000000001ULL);                 /* sNaN */
    71→    emit_u(0xfff8000000000000ULL);                 /* -qNaN */
    72→    emit_u(0x7ff0000000000000ULL);                 /* +Inf: log(Inf) = Inf */
    73→    emit_u(0xfff0000000000000ULL);                 /* -Inf: log(-Inf) = NaN */
    74→    emit_u(0xbff0000000000000ULL);                 /* -1.0: domain error -> NaN */
    75→
    76→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    77→    /* Valid inputs; log produces very large negative results */
    78→    emit_u(0x0000000000000001ULL);                 /* min positive subnormal: 2^-1074 */
    79→    emit_u(0x8000000000000001ULL);                 /* min negative subnormal: domain error */
    80→    emit_u(0x0008000000000000ULL);                 /* mid subnormal */
    81→    emit_u(0x8008000000000000ULL);                 /* -mid subnormal: domain error */
    82→    emit_u(0x000fffffffffffffULL);                 /* max subnormal: just below DBL_MIN */
    83→    emit_u(0x800fffffffffffffULL);                 /* -max subnormal: domain error */
    84→
    85→    /* --- Section 3: Normal boundary values (4) --- */
    86→    emit(DBL_MIN);                                 /* 2^-1022: smallest normal */
    87→    emit(-DBL_MIN);                                /* negative: domain error -> NaN */
    88→    emit_u(0x0010000000000001ULL);                 /* one ULP above DBL_MIN */
    89→    emit(DBL_MAX);                                 /* 0x7fefffffffffffff: largest normal */
    90→
    91→    /* --- Section 4: ULP neighbors of 1.0 (10) --- */
    92→    /* log(1.0) = 0 exactly; critical precision zone */
    93→    emit_u(0x3fefffffffffffffULL);                 /* one ULP below 1.0 */
    94→    emit(1.0);                                     /* log(1) = 0 exactly */
    95→    emit_u(0x3ff0000000000001ULL);                 /* one ULP above 1.0 */
    96→    emit_u(0x3feffffffffffffeULL);                 /* two ULPs below 1.0 */
    97→    emit_u(0x3ff0000000000002ULL);                 /* two ULPs above 1.0 */
    98→    emit_u(0x3fefffffffffffc0ULL);                 /* several ULPs below 1.0 */
    99→    emit_u(0x3ff0000000000040ULL);                 /* several ULPs above 1.0 */
   100→    emit_u(0x3feffffffffffb00ULL);                 /* ~2^-10 below 1.0 */
   101→    emit_u(0x3ff0000000000500ULL);                 /* ~2^-10 above 1.0 */
   102→    emit_u(0x3feffffffffffff0ULL);                 /* 16 ULPs below 1.0 */
   103→
   104→    /* --- Section 5: Mathematical constants (12) --- */
   105→    emit(2.718281828459045);                       /* e: log(e) = 1 */
   106→    emit(2.0);                                     /* log(2) = ln2 */
   107→    emit(0.5);                                     /* log(0.5) = -ln2 */
   108→    emit(10.0);                                    /* log(10) = ln10 */
   109→    emit(0.1);                                     /* log(0.1) = -ln10 */
   110→    emit_u(0x3fe62e42fefa39efULL);                 /* ln2 ~ 0.6931: log(ln2) */
   111→    emit_u(0x4000000000000000ULL);                 /* 2.0 exact bit pattern */
   112→    emit(4.0);                                     /* log(4) = 2*ln2 */
   113→    emit(0.25);                                    /* log(0.25) = -2*ln2 */
   114→    emit(7.38905609893065);                        /* e^2: log(e^2) = 2 */
   115→    emit(1.0 / 2.718281828459045);                 /* 1/e: log(1/e) = -1 */
   116→    emit(2.302585092994046);                       /* ln10: log(ln10) */
   117→
   118→    /* --- Section 6: Powers of 2 (14) --- */
   119→    /* log(2^n) = n*ln2; exercises exponent extraction */
   120→    emit_u(0x4010000000000000ULL);                 /* 4.0 = 2^2 */
   121→    emit_u(0x4020000000000000ULL);                 /* 8.0 = 2^3 */
   122→    emit_u(0x4030000000000000ULL);                 /* 16.0 = 2^4 */
   123→    emit_u(0x4060000000000000ULL);                 /* 128.0 = 2^7 */
   124→    emit_u(0x4090000000000000ULL);                 /* 1024.0 = 2^10 */
   125→    emit_u(0x40f0000000000000ULL);                 /* 32768.0 = 2^15 */
   126→    emit_u(0x4330000000000000ULL);                 /* 2^52: mantissa precision boundary */
   127→    emit_u(0x7fe0000000000000ULL);                 /* 2^1023: near DBL_MAX */
   128→    emit_u(0x3fe0000000000000ULL);                 /* 0.5 = 2^-1 exact */
   129→    emit_u(0x3fd0000000000000ULL);                 /* 0.25 = 2^-2 exact */
   130→    emit_u(0x3fb0000000000000ULL);                 /* 2^-4 = 0.0625 */
   131→    emit_u(0x3f50000000000000ULL);                 /* 2^-10 */
   132→    emit_u(0x3c00000000000000ULL);                 /* 2^-63 */
   133→    emit_u(0x0020000000000000ULL);                 /* 2^-1021: near DBL_MIN */
   134→
   135→    /* --- Section 7: Near-zero inputs (8) --- */
   136→    /* log(x) is large negative; exercises underflow/denormal result path */
   137→    emit(1.0e-10);
   138→    emit(1.0e-20);
   139→    emit(1.0e-50);
   140→    emit(1.0e-100);
   141→    emit(1.0e-150);
   142→    emit(1.0e-200);
   143→    emit(1.0e-300);
   144→    emit_u(0x0010000000000000ULL);                 /* DBL_MIN = 2^-1022 */
   145→
   146→    /* --- Section 8: Large values (8) --- */
   147→    /* log(x) grows slowly; tests large-exponent path */
   148→    emit(1.0e10);
   149→    emit(1.0e50);
   150→    emit(1.0e100);
   151→    emit(1.0e150);
   152→    emit(1.0e200);
   153→    emit(1.0e250);
   154→    emit(1.0e300);
   155→    emit_u(0x7fefffffffffffffULL);                 /* DBL_MAX */
   156→
   157→    /* --- Section 9: Negative inputs / domain errors (10) --- */
   158→    /* All return NaN; exercises error-handling path */
   159→    emit(-1.0);
   160→    emit(-2.0);
   161→    emit(-0.5);
   162→    emit(-10.0);
   163→    emit(-1.0e-10);
   164→    emit(-1.0e10);
   165→    emit(-1.0e100);
   166→    emit_u(0xc000000000000000ULL);                 /* -2.0 exact */
   167→    emit_u(0xbfe0000000000000ULL);                 /* -0.5 exact */
   168→    emit_u(0xc024000000000000ULL);                 /* -10.0 exact */
   169→
   170→    /* --- Section 10: Near-1.0 arithmetic offsets (20) --- */
   171→    /* Exercises the log(1+x) ~ x Taylor series path for |x| << 1 */
   172→    emit(1.0 + 1.0e-4);
   173→    emit(1.0 - 1.0e-4);
   174→    emit(1.0 + 1.0e-6);
   175→    emit(1.0 - 1.0e-6);
   176→    emit(1.0 + 1.0e-8);
   177→    emit(1.0 - 1.0e-8);
   178→    emit(1.0 + 1.0e-10);
   179→    emit(1.0 - 1.0e-10);
   180→    emit(1.0 + 1.0e-12);
   181→    emit(1.0 - 1.0e-12);
   182→    emit(1.0 + 1.0e-14);
   183→    emit(1.0 - 1.0e-14);
   184→    emit(1.0 + 1.0e-15);
   185→    emit(1.0 - 1.0e-15);
   186→    emit(1.0 + 0.001);
   187→    emit(1.0 - 0.001);
   188→    emit(1.0 + 0.01);
   189→    emit(1.0 - 0.01);
   190→    emit(1.0 + 0.1);
   191→    emit(1.0 - 0.1);
   192→}
