   194→/* ------------------------------------------------------------------ */
   195→
   196→/* Sweep [0.1, 10.0] in 200 steps each direction */
   197→#ifndef EN_PERF
   198→static void test_sweep(void)
   199→{
   200→    double lo = 0.1;
   201→    double hi = 10.0;
   202→    int nsteps = 200;
   203→    double step = (hi - lo) / (double)nsteps;
   204→
   205→    /* [0.1, 10.0] */
   206→    for (int i = 0; i <= nsteps; i++)
   207→        emit(lo + (double)i * step);
   208→
   209→    /* [10.0, 0.1] (decreasing) */
   210→    for (int i = 0; i <= nsteps; i++)
   211→        emit(hi - (double)i * step);
   212→}
   213→
   214→/* Sample near 1.0: [0.99999, 1.00001] every 2^45 ULP */
   215→static void test_exhaustive_small(void)
   216→{
   217→    uint64_t center = 0x3ff0000000000000ULL; /* 1.0 */
   218→    uint64_t radius = (1ULL << 18); /* ~131k ULP from 1.0 */
   219→    uint64_t step = 1ULL << 45;
   220→
   221→    for (uint64_t b = center - radius; b <= center + radius; b += step)
   222→        emit_u(b);
   223→}
   224→#endif
   225→
   226→/* ------------------------------------------------------------------ */
   227→
   228→int main(void)
   229→{
   230→#ifdef EN_PERF
